class Solution:
    def waysToFillArray(self, queries):
        MOD = 10**9 + 7
        res = []
        for n, k in queries:
            # factorize k
            factors = {}
            x = k
            d = 2
            while d * d <= x:
                while x % d == 0:
                    factors[d] = factors.get(d, 0) + 1
                    x //= d
                d += 1
            if x > 1:
                factors[x] = factors.get(x, 0) + 1
            ans = 1
            for e in factors.values():
                # C(e+n-1, e) by multiplicative formula mod MOD
                num = 1
                den = 1
                for i in range(e):
                    num = num * ((n - 1 + e - i) % MOD) % MOD
                    den = den * (i + 1) % MOD
                ans = ans * num % MOD * pow(den, MOD - 2, MOD) % MOD
            res.append(ans)
        return res

