class Solution:
    def waysToFillArray(self, queries):
        MOD = 10**9 + 7
        MAXV = 10000
        spf = list(range(MAXV + 1))
        i = 2
        while i * i <= MAXV:
            if spf[i] == i:
                for j in range(i * i, MAXV + 1, i):
                    if spf[j] == j:
                        spf[j] = i
            i += 1
        LIM = MAXV + 20
        fact = [1] * LIM
        for t in range(1, LIM):
            fact[t] = fact[t - 1] * t % MOD
        inv = [1] * LIM
        inv[LIM - 1] = pow(fact[LIM - 1], MOD - 2, MOD)
        for t in range(LIM - 2, -1, -1):
            inv[t] = inv[t + 1] * (t + 1) % MOD
        def comb(a, b):
            if b < 0 or b > a:
                return 0
            return fact[a] * inv[b] % MOD * inv[a - b] % MOD
        res = []
        for n, k in queries:
            ans = 1
            while k > 1:
                p = spf[k]
                e = 0
                while k % p == 0:
                    k //= p
                    e += 1
                ans = ans * comb(e + n - 1, e) % MOD
            res.append(ans)
        return res

