var waysToFillArray = function(queries) {
    const MOD = 1000000007n;
    const MAXV = 10000;
    const spf = new Array(MAXV + 1);
    for (let i = 0; i <= MAXV; i++) spf[i] = i;
    for (let i = 2; i * i <= MAXV; i++) {
        if (spf[i] === i) {
            for (let j = i * i; j <= MAXV; j += i) if (spf[j] === j) spf[j] = i;
        }
    }
    const LIM = MAXV + 20;
    const fact = new Array(LIM);
    fact[0] = 1n;
    for (let t = 1; t < LIM; t++) fact[t] = (fact[t - 1] * BigInt(t)) % MOD;
    const power = (b, e) => {
        let r = 1n; b %= MOD;
        while (e > 0n) { if (e & 1n) r = (r * b) % MOD; b = (b * b) % MOD; e >>= 1n; }
        return r;
    };
    const inv = new Array(LIM);
    inv[LIM - 1] = power(fact[LIM - 1], MOD - 2n);
    for (let t = LIM - 2; t >= 0; t--) inv[t] = (inv[t + 1] * BigInt(t + 1)) % MOD;
    const comb = (a, b) => {
        if (b < 0 || b > a) return 0n;
        return (fact[a] * inv[b] % MOD) * inv[a - b] % MOD;
    };
    const res = [];
    for (const [n, k0] of queries) {
        let k = k0;
        let ans = 1n;
        while (k > 1) {
            const p = spf[k];
            let e = 0;
            while (k % p === 0) { k = Math.floor(k / p); e++; }
            ans = (ans * comb(e + n - 1, e)) % MOD;
        }
        res.push(Number(ans));
    }
    return res;
};
